SELECT famsize, description
FROM family_sizes
WHERE famsize = 'LE3';

SELECT reason
FROM student_reasons
WHERE influence_level = 'medium';

SELECT COUNT(student_id) AS number_of_students
FROM student_reasons
WHERE reason = 'course';

SELECT COUNT(student_id) AS weekly_drinkers
FROM drinking_habits
WHERE drinking_frequency = 'weekly';

SELECT student_id, drinking_frequency
FROM drinking_habits
WHERE drinking_frequency = 'weekly';
